class Solution {
public:
    int sumOfPrimesInRange(int n) {
        int r = 0;
        int tmp = n;
        while (tmp) {
            r = r * 10 + tmp % 10;
            tmp /= 10;
        }
        int low = min(n, r);
        int high = max(n, r);
        int ans = 0;
        for (int x = low; x <= high; ++x) {
            if (isPrime[x]) ans += x;
        }
        return ans;
    }
};

