function sumOfPrimesInRange(n: number): number {
    const r = parseInt(n.toString().split('').reverse().join(''));
    const low = Math.min(n, r);
    const high = Math.max(n, r);
    let sum = 0;
    for (let x = low; x <= high; x++) {
        if (isPrime[x]) sum += x;
    }
    return sum;
}
